-- в”Ђв”Ђ Kroki в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Kroki is a free, open-source API that renders text-based markup into diagrams, supporting over 20 diagram types through one unified endpoint.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Kroki Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Kroki review: the free, open-source diagrams-as-code API's supported diagram types, self-hosting, integrations, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Kroki is a free and open-source unified API for generating diagrams from plain-text markup, created by French software engineer Guillaume Grossetie and published under the GitHub organization yuzutech, with the project first launched publicly in April 2019. Kroki is released under the MIT license and has grown into a community project with thousands of GitHub stars and dozens of contributors. The core idea behind Kroki is to solve the fragmentation problem in diagrams-as-code tooling: rather than installing and maintaining separate renderers for each diagram syntax a team might want to use, Kroki exposes a single HTTP API that accepts text written in any of more than 20 supported diagram languages and returns a rendered image. Supported diagram types include widely used options such as Mermaid, PlantUML, GraphViz, BPMN, C4, Ditaa, Excalidraw, Vega and Vega-Lite, WaveDrom, Nomnoml, Pikchr, SvgBob, UMLet, Symbolator, DBML, Bytefield, BlockDiag, Erd, and Diagrams.net (draw.io), among others, with new diagram types added over time. Architecturally, Kroki supports both GET and POST requests: for GET requests, the diagram source is compressed with deflate and base64-encoded directly into the URL path in the form of /{diagram_type}/{output_format}/{encoded_diagram}, which makes it easy to embed live diagram links in documentation or Markdown files, while POST requests allow larger raw diagram text to be submitted directly in the request body. Output formats vary by diagram type but commonly include SVG, PNG, PDF, and JPEG. Kroki's architecture is deliberately modular: diagram types that depend on third-party rendering engines, such as Excalidraw, Structurizr, or Pikchr, run as separate companion microservices rather than being baked into the core Kroki server, which lets the project add support for new diagram tools without destabilizing the core system. Because Kroki is open source and ships as Docker images, including the companion service containers, organizations that need to keep proprietary architecture or sequence diagrams off third-party infrastructure can self-host the entire stack behind their own firewall using Docker or Docker Compose. For users who don't need to self-host, the project also operates a free public instance at kroki.io that anyone can call directly without installing anything, making it simple to prototype or use Kroki in low-volume personal or open-source projects. Kroki has built an ecosystem of official and community integrations that embed its rendering directly into documentation tooling, including plugins for Asciidoctor, MkDocs, and Confluence (via a dedicated Kroki Diagrams for Confluence marketplace app), letting technical writers and developers keep diagrams as version-controlled text alongside their documentation rather than maintaining separate binary image files that drift out of sync with the underlying system they describe. Because Kroki has no company behind it in the traditional commercial sense, it does not have named pricing tiers, funding rounds, or a formal headquarters; it is entirely free to use, whether through the public API or a self-hosted deployment, and third-party managed hosting providers such as Elestio offer paid, fully-managed Kroki instances for teams that want the self-hosted assurance without operating the infrastructure themselves. Kroki's primary competitors are the individual diagram renderers it wraps and orchestrates, such as running PlantUML, Mermaid, or GraphViz directly via their own native command-line tools or dedicated hosted services, as well as commercial diagramming platforms like Lucidchart, draw.io/diagrams.net, and Mermaid Live/Mermaid Chart; Kroki differentiates itself from these by being diagram-syntax agnostic and API-first, giving developers and technical writers a single consistent integration point regardless of which text-based diagram language a project or team standardizes on, rather than locking them into one specific diagram syntax or a proprietary visual editor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd01ba1ee-34ac-4433-8e64-30da756ce4a2';

