INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$AI Noise Cancellation$q$, $q$Removes background noise and echo from both microphone and speaker audio in real time using on-device deep learning models.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Background Voice Cancellation$q$, $q$Filters out other people talking in the same room so only the primary speaker's voice comes through on a call.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$AI Meeting Assistant$q$, $q$Joins or listens to calls to produce live transcripts, AI-generated summaries, and action items.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Meeting Recording and History$q$, $q$Records audio and video of calls and stores a searchable meeting history in one place.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$App-Agnostic Integration$q$, $q$Works as a virtual microphone and speaker layer with Zoom, Google Meet, Microsoft Teams, Slack huddles, and most VoIP or call center software.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$On-Device Privacy Architecture$q$, $q$Processes audio locally on the device rather than streaming it to the cloud, supporting HIPAA and GDPR compliant use on paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$CRM and Business Integrations$q$, $q$Business plan adds CRM integrations, SSO, and expanded storage for team-wide deployment.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Enterprise Admin Controls$q$, $q$Centralized admin dashboard, organization-wide analytics, and custom security policies for large deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Effective real-time noise and voice cancellation that works across virtually any calling app$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Free tier is genuinely usable for individuals with a daily minute allowance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$On-device processing model appeals to privacy- and compliance-conscious users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$AI meeting summaries and action items reduce manual note-taking$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Lightweight desktop app with a low learning curve$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Free plan is capped at 60 minutes of noise cancellation per day$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Transcription and AI meeting features require a paid Pro or Business plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Enterprise tier has no published price and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Primarily an audio and meeting-intelligence layer rather than a full conferencing replacement$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Desktop app must run continuously in the background to filter audio$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$What does Krisp actually do?$q$, $q$Krisp is a desktop and mobile app that sits between your microphone and speakers and any calling app, using on-device AI to strip out background noise, echo, and other people's voices, while its AI meeting assistant can transcribe calls and generate summaries.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Is Krisp free?$q$, $q$Yes, Krisp offers a free plan with 60 minutes of noise cancellation per day; unlimited noise cancellation and AI meeting features require the Pro plan starting at $8/month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Does Krisp work with Zoom, Google Meet, and Microsoft Teams?$q$, $q$Yes, Krisp is app-agnostic and works with virtually any conferencing or calling software, including Zoom, Google Meet, Microsoft Teams, and Slack huddles.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Is my audio sent to Krisp's servers?$q$, $q$Krisp markets its noise cancellation as processed locally on-device, which is part of why it supports HIPAA and GDPR compliant use on paid plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Who founded Krisp and when?$q$, $q$Krisp was founded in 2017 by Davit Baghdasaryan and Artavazd Minasyan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$What are the main alternatives to Krisp?$q$, $q$Common alternatives include Otter.ai, Fireflies.ai, Fathom, and Nyota, though most of these focus primarily on transcription rather than Krisp's core strength of audio noise cancellation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Remote and hybrid team meetings$q$, $q$Eliminates keyboard clicks, dogs barking, traffic, and other household noise during video calls.$q$, $q$Remote knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Sales and support call centers$q$, $q$Cleans up agent and customer audio while producing call summaries and searchable meeting history for coaching and CRM logging.$q$, $q$Sales reps and customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Regulated industries$q$, $q$Business and Enterprise tiers support HIPAA and GDPR-aligned handling of call audio, plus SSO and admin controls for organization-wide deployment.$q$, $q$Compliance-conscious enterprises in healthcare, legal, and finance$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["60 minutes/day of noise cancellation","Works with any calling app","Basic call clarity tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Pro$q$, $q$$8/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited noise cancellation","Unlimited AI summaries and action items","Meeting history","Audio and video recording","HIPAA and GDPR compliant handling"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Business$q$, $q$$15/month$q$, $q$Monthly, per seat$q$, NULL, $q$["Everything in Pro","CRM integrations","SSO","Expanded storage","Team management and admin controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Centralized admin dashboard","Organization-wide analytics","SSO","Centralized billing","Custom security policies"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Krisp is a desktop, mobile, and browser-integrated application built to solve a specific, common problem in remote work: noisy, unprofessional-sounding calls. Founded in 2017 by Davit Baghdasaryan and Artavazd Minasyan, the company built its core technology around on-device deep learning models that strip out background noise, echo, and even competing voices from a room, so that only the primary speaker comes through clearly on a call.$q$, $q$Because Krisp operates at the audio-driver level rather than inside any single conferencing app, it works across virtually any tool a team already uses, from Zoom and Google Meet to Microsoft Teams, Slack huddles, and call center software. Over time the company has layered an AI meeting assistant on top of this audio foundation, adding live transcription, AI-generated summaries, action items, and recording, which moves Krisp from a pure noise-cancellation utility toward a broader meeting productivity tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Krisp's signature capability is real-time AI noise cancellation, which removes background sounds like keyboard clicks, traffic, barking dogs, and construction noise from both the microphone and speaker side of a call, along with Background Voice Cancellation, which filters out other people talking nearby so only the intended speaker is heard. Its AI meeting assistant extends this into transcription, AI-written summaries, and action-item extraction, paired with audio and video recording and a searchable meeting history.$q$, $q$On the compliance and enterprise side, Krisp supports HIPAA and GDPR-aligned handling of call audio on paid plans, along with single sign-on, CRM integrations, and a centralized admin dashboard with team analytics for larger deployments. Krisp positions its on-device processing architecture as a privacy advantage relative to cloud-first transcription tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Krisp uses a four-tier freemium model. The Free plan includes 60 minutes per day of noise cancellation but no transcription, summaries, or recording. The Pro plan, at $8 per month, removes the daily noise-cancellation limit and adds unlimited AI summaries, action items, meeting history, and recording. The Business plan, at $15 per month, layers on CRM integrations, SSO, expanded storage, and team management, while Enterprise pricing is negotiated and adds centralized billing, organization-wide analytics, and custom security policies.$q$, $q$A seven-day free trial unlocks all paid functionality, including unlimited transcription and recording, letting prospective customers evaluate the full feature set before committing to Pro, Business, or Enterprise.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
