INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7e673235-0981-4c36-a2e4-4e051b04105c', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Advanced Brush Engine$q$, $q$Dozens of customizable brush engines, including pixel, smudge, particle, and shape engines, with pressure and tilt sensitivity for pen tablets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Non-Destructive Layers and Masks$q$, $q$Group-based layer management, layer styles, clone layers, and filter or transform masks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Animation Timeline$q$, $q$Frame-by-frame animation docker with onion skinning and export to GIF, WebM, and image sequences.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Vector and Text Tools$q$, $q$Vector layers for shapes and text alongside raster painting in the same document.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Wide Color Management$q$, $q$Support for RGB, CMYK, and HDR color spaces for print and high-dynamic-range work.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Python Scripting and Plugins$q$, $q$A scripting API that lets users automate tasks and build custom plugins and dockers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Painting Assistants$q$, $q$Perspective grids, rulers, and vanishing-point guides for technical and comic art.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Resource Bundles$q$, $q$Bundle-based sharing of brushes, palettes, gradients, and templates between artists.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Completely free with no subscriptions, watermarks, or feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Professional-grade brush engine rivals paid competitors like Photoshop and Procreate$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Fully open source under GPL v3 so the code can be audited, modified, and redistributed$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Built-in animation tools remove the need for a separate 2D animation app$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Active community and frequent releases funded by a nonprofit foundation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$No built-in cloud collaboration or sync comparable to some commercial apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Steeper learning curve for beginners compared to simplified apps like Procreate$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$No official iOS or iPad app, only Android/ChromeOS on mobile$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Relies on donations and optional store purchases, so development pace depends on funding$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Advanced typography and print-production features lag behind Adobe Illustrator or Photoshop$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Is Krita really free?$q$, $q$Yes, Krita is completely free and open source under the GNU General Public License v3; the versions sold on Steam, the Microsoft Store, or Google Play are optional paid copies that fund development, but the identical software is always free at krita.org.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$What is Krita mainly used for?$q$, $q$Krita is used for digital painting, illustration, concept art, comics, and 2D frame-by-frame animation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Does Krita run on Mac and Linux?$q$, $q$Yes, Krita runs on Windows, macOS, Linux (via distribution packages or AppImage), and Android/ChromeOS.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Who develops Krita?$q$, $q$Krita is developed by a community of contributors coordinated by the nonprofit Krita Foundation, based in Deventer, Netherlands, with Dmitry Kazakov as lead developer.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$How is Krita different from GIMP or Photoshop?$q$, $q$Unlike GIMP, which is a general-purpose image editor, Krita is purpose-built for painting and illustration with tablet-focused brush engines and animation tools; unlike Photoshop, it is free, open source, and has no subscription.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Does Krita support Python scripting?$q$, $q$Yes, Krita includes a Python scripting API that lets users automate tasks and build custom plugins and dockers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Digital illustration and concept art$q$, $q$Professional brush engine and layer tools for painting original artwork and game or film concept art.$q$, $q$Illustrators and concept artists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Comic and webcomic creation$q$, $q$Vector text, panel templates, and perspective assistants streamline comic page production.$q$, $q$Comic artists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$2D animation$q$, $q$Built-in timeline, onion skinning, and export to GIF, WebM, and image sequences support short-form frame-by-frame animation without extra software.$q$, $q$Independent animators and students$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Free (Official Download)$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Full feature set","No watermarks or subscriptions","GPL v3 open-source license","Available on krita.org for Windows, macOS, and Linux"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$Store Version (Steam, Microsoft Store, Google Play)$q$, $q$Around $9.99, one-time (optional)$q$, $q$One-time$q$, NULL, $q$["Identical software to the free download","Automatic updates through the store","Purchase price supports Krita Foundation development"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Krita is a free and open-source raster graphics editor purpose-built for digital painting, illustration, and 2D animation. Its roots go back to 1999 as a KDE community project called KImageShop, which was renamed twice for trademark reasons before settling on the name Krita in 2002, with the first public release arriving as part of KOffice 1.4 in 2004.$q$, $q$Since 2012, development has been coordinated by the nonprofit Krita Foundation in Deventer, Netherlands, led by lead developer Dmitry Kazakov. The software is licensed under the GNU General Public License v3, so it is always free to download, use, and modify, with paid copies on stores like Steam functioning as optional donations rather than a separate paid tier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Krita's core strength is its brush engine system, which includes more than a dozen engines (pixel, smudge, particle, shape, and texture, among others) with full pressure and tilt sensitivity for graphics tablets, plus wide colour-space support including CMYK and HDR that is uncommon among free painting tools. Non-destructive layers, layer groups, masks, and combined vector-and-raster editing round out its core painting toolkit.$q$, $q$Beyond static illustration, Krita ships a complete animation module with a frame-by-frame timeline, onion skinning, and export to GIF, WebM, and image sequences, plus painting assistants like perspective grids for technical and comic art. A built-in Python scripting API allows advanced users to automate workflows and build custom plugins.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Krita is entirely free under the GPL v3 license when downloaded directly from krita.org, with no subscription, trial period, or feature paywall of any kind. The full, identical application can also be purchased on storefronts like Steam, the Microsoft Store, and Google Play for a modest one-time price, historically around $9.99.$q$, $q$These storefront purchases function as an optional way to support the Krita Foundation's development work and receive automatic updates through the store, not as a separate paid edition with extra features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4d6dd956-9199-4e06-b14d-777578701617', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Unified Diagram API$q$, $q$A single HTTP endpoint renders 20+ text-based diagram languages, including Mermaid, PlantUML, GraphViz, BPMN, C4, Excalidraw, and Vega-Lite.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$GET and POST Endpoints$q$, $q$Supports lightweight GET requests with deflate-compressed, base64-encoded diagram source in the URL, and POST requests with raw diagram text for larger diagrams.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Multiple Output Formats$q$, $q$Renders diagrams to SVG, PNG, PDF, or JPEG depending on the diagram type.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Self-Hosted Docker Deployment$q$, $q$Ships as Docker images, including companion service containers, so teams can run Kroki entirely on their own infrastructure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Free Public Instance$q$, $q$kroki.io hosts a free public API so users can try or use the service without installing anything.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Documentation Tool Integrations$q$, $q$Official plugins for tools like Asciidoctor, MkDocs, and Confluence to embed diagrams directly in docs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Modular Companion Services$q$, $q$Diagram types that need external tools, such as Excalidraw, Structurizr, or Pikchr, run as separate companion microservices for easy extension.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$MIT-Licensed Open Source$q$, $q$Source hosted on GitHub under the MIT license with active community contributions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Free to use, both as a self-hosted service and via the public kroki.io API$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$One API covers dozens of diagram-as-code syntaxes instead of installing separate renderers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Docker-based self-hosting keeps proprietary diagrams off third-party servers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Wide ecosystem of plugins for documentation tools like Asciidoctor, MkDocs, and Confluence$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Actively maintained open-source project with a permissive MIT license$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$No official SaaS support contract or SLA, since it is a community open-source project$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Self-hosting the full set of diagram types requires running multiple companion containers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Complex diagrams can render slowly on the free public instance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$No built-in visual, WYSIWYG diagram editor, since input is text-based markup$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Documentation assumes familiarity with the underlying diagram syntaxes, such as PlantUML or Mermaid$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$What is Kroki?$q$, $q$Kroki is a free, open-source API that converts plain-text diagram descriptions, written in languages like Mermaid, PlantUML, or GraphViz, into rendered images such as SVG or PNG.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Do I need to install anything to use Kroki?$q$, $q$No, you can call the free public API at kroki.io directly, or self-host Kroki with Docker if you need full control over your infrastructure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Which diagram types does Kroki support?$q$, $q$Kroki supports more than 20 diagram types, including Mermaid, PlantUML, GraphViz, BPMN, C4, Excalidraw, Ditaa, Vega, Vega-Lite, WaveDrom, and Diagrams.net (draw.io).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Is Kroki free?$q$, $q$Yes, Kroki is completely free and open source under the MIT license, both for the hosted public instance and for self-hosted deployments.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Who maintains Kroki?$q$, $q$Kroki is maintained under the GitHub organization yuzutech, created by Guillaume Grossetie, and was first published in 2019.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Can Kroki be embedded in documentation tools?$q$, $q$Yes, Kroki has integrations for tools such as Asciidoctor, MkDocs, and Confluence, letting teams embed diagrams-as-code directly in their docs.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Docs-as-code diagramming$q$, $q$Embed version-controlled, text-based diagrams directly in Markdown or AsciiDoc documentation instead of maintaining binary image files.$q$, $q$Technical writers and developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Internal developer platforms$q$, $q$Self-host Kroki behind a firewall so architecture and sequence diagrams never leave internal infrastructure.$q$, $q$Platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Automated diagram generation in CI/CD$q$, $q$Call the Kroki API from build pipelines to regenerate architecture or pipeline diagrams automatically whenever source text changes.$q$, $q$DevOps engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$Free (Public API or Self-Hosted)$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Access to all supported diagram types","GET and POST rendering endpoints","Docker images for self-hosting","MIT license"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kroki is a free, open-source API that converts plain-text diagram descriptions into rendered images. Created by Guillaume Grossetie under the yuzutech GitHub organization and first published in April 2019, it is released under the MIT license and has grown through community contributions into a project supporting more than 20 diagram-as-code languages.$q$, $q$Rather than requiring separate tooling for each diagram syntax, Kroki exposes one unified HTTP endpoint that accepts markup in languages like Mermaid, PlantUML, or GraphViz and returns SVG, PNG, PDF, or JPEG output, making it a common building block behind documentation sites and internal developer tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kroki supports GET requests with deflate-compressed, base64-encoded diagram source embedded directly in the URL, ideal for linking live diagrams from Markdown or wiki pages, as well as POST requests for larger diagram text. Its modular architecture runs diagram types that need external engines, such as Excalidraw or Structurizr, as separate companion microservices, which keeps the core service lean while still supporting a wide range of syntaxes.$q$, $q$Because Kroki ships as Docker images, teams can self-host it entirely on their own infrastructure to keep sensitive architecture diagrams private, or use the free public instance at kroki.io for quick, no-install access. Official integrations with tools like Asciidoctor, MkDocs, and Confluence let teams embed diagrams-as-code directly into their existing documentation workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kroki itself is entirely free, both as the publicly hosted kroki.io API and as a self-hosted Docker deployment, since it is an open-source, MIT-licensed community project rather than a commercial product with pricing tiers.$q$, $q$Teams that want a fully managed, self-hosted-equivalent instance without operating the Docker infrastructure themselves can turn to third-party managed hosting providers, such as Elestio, which offer paid hosting plans for Kroki as one of many open-source tools in their catalog.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d01ba1ee-34ac-4433-8e64-30da756ce4a2', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Kubeflow Notebooks$q$, $q$Hosted Jupyter notebook environments for interactive model development running directly inside the cluster.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Kubeflow Pipelines$q$, $q$A workflow engine for building, deploying, and tracking reproducible, containerized ML pipelines.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Training Operators$q$, $q$Kubernetes-native operators for distributed training of TensorFlow, PyTorch, XGBoost, and other frameworks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Katib$q$, $q$Automated hyperparameter tuning and neural architecture search built on Kubernetes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$KServe Model Serving$q$, $q$A standardized, autoscaling model-serving component for deploying trained models as inference endpoints.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Central Dashboard and Multi-Tenancy$q$, $q$A web UI plus namespace-based isolation for teams sharing a cluster.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Framework Agnostic$q$, $q$Supports TensorFlow, PyTorch, MXNet, XGBoost, and other popular ML frameworks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Portable Across Clouds$q$, $q$Runs on any conformant Kubernetes cluster, on-premises or across major managed Kubernetes services.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Free, open-source, and fully portable across any Kubernetes distribution or cloud$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Covers the full ML lifecycle from notebooks to training to tuning to serving in one toolkit$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Framework-agnostic, supporting TensorFlow, PyTorch, and other major libraries$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Backed by a large multi-company community and now a CNCF incubating project$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Reproducible, containerized pipelines improve collaboration and auditability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Steep setup and operational complexity, requiring solid Kubernetes expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Frequent component changes between releases can complicate long-term upgrades$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Resource-heavy to run compared to lighter-weight ML pipeline tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Documentation and UX vary in polish across the many sub-projects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$No commercial support included; enterprises typically need a managed distribution or in-house platform team$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$What is Kubeflow used for?$q$, $q$Kubeflow is used to build, train, tune, and deploy machine learning models as reproducible, containerized workflows running on Kubernetes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Who created Kubeflow?$q$, $q$Kubeflow was created in 2017 by Google engineers, including David Aronchick, Jeremy Lewi, and Vishnu Kannan, originally to run TensorFlow workloads at scale on Kubernetes.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Is Kubeflow free?$q$, $q$Yes, Kubeflow is fully open source and free to use; costs come from the underlying Kubernetes infrastructure it runs on.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Does Kubeflow require Kubernetes expertise?$q$, $q$Yes, deploying and operating Kubeflow assumes familiarity with Kubernetes concepts like pods, custom resources, and namespaces.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Is Kubeflow part of the CNCF?$q$, $q$Yes, Kubeflow was accepted as a CNCF incubating project in July 2023.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$What ML frameworks does Kubeflow support?$q$, $q$Kubeflow supports TensorFlow, PyTorch, XGBoost, Apache MXNet, and other popular machine learning frameworks through its training operators.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Enterprise MLOps platforms$q$, $q$Standardize how data scientists across an organization train, tune, and deploy models on shared Kubernetes infrastructure.$q$, $q$ML platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Distributed model training$q$, $q$Use training operators to run distributed TensorFlow or PyTorch training jobs across multiple nodes and GPUs.$q$, $q$ML researchers and engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Reproducible ML pipelines$q$, $q$Use Kubeflow Pipelines to version and re-run containerized, multi-step training and evaluation workflows.$q$, $q$Data science teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$Free (Open Source)$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Full access to Notebooks, Pipelines, Training Operators, Katib, and KServe","Self-hosted on any conformant Kubernetes cluster","Community support via Slack and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kubeflow is an open-source toolkit for running the machine learning lifecycle, from notebooks to distributed training to hyperparameter tuning to model serving, as Kubernetes-native, containerized workflows. It was created in 2017 by Google engineers David Aronchick, Jeremy Lewi, and Vishnu Kannan to generalize the internal pattern Google used for running TensorFlow at scale on Kubernetes.$q$, $q$Kubeflow has since grown into a broad, multi-vendor community project with contributors from more than 150 companies, and in July 2023 the CNCF accepted it as an incubating project, placing its governance alongside Kubernetes, Prometheus, and other major cloud-native infrastructure projects.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kubeflow is organized as a set of composable components: Kubeflow Notebooks for hosted, multi-user Jupyter environments; Kubeflow Pipelines for defining and versioning reproducible, multi-step ML workflows; the Training Operator for distributed training across TensorFlow, PyTorch, XGBoost, and other frameworks; Katib for automated hyperparameter tuning and neural architecture search; and KServe for standardized, autoscaling model serving with canary rollout support.$q$, $q$A central dashboard and namespace-based multi-tenancy let multiple data science teams share a single Kubernetes cluster with logical isolation, and because every component runs as native Kubernetes resources, the same Kubeflow deployment can run identically on-premises or across any major cloud provider's Kubernetes service.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kubeflow itself carries no license fee or subscription cost, since it is fully open source and distributed as Kubernetes manifests and deployment tooling that any team can install on their own cluster.$q$, $q$The real cost of running Kubeflow comes from the underlying Kubernetes infrastructure and compute (CPUs, GPUs, and storage) it consumes, plus the engineering time required to operate and secure the cluster, which is why many organizations use a managed Kubernetes service or a commercial Kubeflow distribution to reduce operational overhead.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('47cd8f03-df02-4827-a41a-94df72cd0222', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$VirtualMachine CRDs$q$, $q$Declarative VirtualMachine, VirtualMachineInstance, and related Kubernetes custom resources for creating and managing VMs like any other cluster object.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Live Migration$q$, $q$Moves running VMs between nodes without downtime using pre-copy memory migration, for maintenance, load balancing, or node failure response.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$virtctl CLI$q$, $q$A companion to kubectl for VM-specific actions like start, stop, pause, console access, and image management.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$KVM/QEMU-Based Virtualization$q$, $q$Runs each VM inside a pod using containerized QEMU and libvirt on top of the Linux KVM hypervisor.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Storage and CSI Integration$q$, $q$Attaches persistent volumes and Kubernetes storage classes to VMs for stateful virtual machine workloads.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Networking via Kubernetes CNI$q$, $q$VMs share the same network plugins and policies used by containerized workloads in the cluster.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Mixed Container and VM Workloads$q$, $q$Lets legacy, non-containerized applications run alongside cloud-native microservices in the same cluster.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$CNCF-Governed Project$q$, $q$Incubating CNCF project with contributors from Red Hat, NVIDIA, SUSE, IBM, and others.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Lets teams run legacy VM workloads on the same Kubernetes control plane as containers, avoiding a separate hypervisor stack$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Free, open source, and governed by the CNCF with broad multi-vendor contribution$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Live migration and VM lifecycle management match many capabilities of traditional hypervisors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Uses the same kubectl-based tooling and RBAC as the rest of the cluster$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Underpins commercial products like Red Hat OpenShift Virtualization, so it has real production mileage$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Requires nodes with hardware virtualization (KVM) support, which not all cloud instances offer by default$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Adds operational complexity on top of an already complex Kubernetes stack$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Feature parity with mature hypervisors like VMware vSphere is still catching up in some areas$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Community support only unless paired with a commercial distribution such as OpenShift Virtualization$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$VM performance tuning and storage configuration require deeper virtualization knowledge than typical container workloads$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$What is KubeVirt used for?$q$, $q$KubeVirt lets Kubernetes clusters run and manage traditional virtual machines alongside containers, which is useful for migrating legacy VM-based applications to a cloud-native platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Who started KubeVirt?$q$, $q$KubeVirt was started at Red Hat around the end of 2016 and formally launched in January 2017.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Is KubeVirt free?$q$, $q$Yes, KubeVirt is a free, open-source CNCF project; commercial support is available through vendors like Red Hat via products such as OpenShift Virtualization.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Does KubeVirt support live migration?$q$, $q$Yes, KubeVirt supports live migration of running VMs between cluster nodes with minimal to no downtime.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$What hypervisor does KubeVirt use under the hood?$q$, $q$KubeVirt runs QEMU and libvirt inside containers, using the Linux kernel's KVM module as the underlying hypervisor.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Is KubeVirt a CNCF project?$q$, $q$Yes, KubeVirt joined the CNCF as a Sandbox project in September 2019 and reached Incubating status in April 2022.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Legacy application migration$q$, $q$Move VM-based legacy applications onto Kubernetes without re-architecting them as containers.$q$, $q$Enterprise infrastructure teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Hybrid VM and container platforms$q$, $q$Run stateful VM workloads and cloud-native microservices side by side under one Kubernetes control plane.$q$, $q$Platform engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Virtual desktop and test-lab infrastructure$q$, $q$Spin up and tear down full VMs on demand for test labs, CI environments, or virtual desktops using Kubernetes-native tooling.$q$, $q$Infrastructure and QA teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$Free (Open Source)$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["VirtualMachine and VirtualMachineInstance CRDs","Live migration","virtctl CLI","Storage and networking integration via Kubernetes CSI and CNI","Community support via CNCF Slack and GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$KubeVirt is an open-source project that lets Kubernetes clusters run and manage traditional virtual machines using the same declarative API and command-line tooling used for containers. It began at Red Hat at the end of 2016 and formally launched in January 2017, aimed at letting organizations run VM-based workloads on Kubernetes without first rewriting them as containers.$q$, $q$The project joined the CNCF as a Sandbox project in September 2019 and reached Incubating maturity in April 2022, with version 1.0 shipping in 2023. It now has contributors from companies including Red Hat, Apple, NVIDIA, SUSE, IBM, and SAP, and underpins commercial products such as Red Hat OpenShift Virtualization.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$KubeVirt extends the Kubernetes API with VirtualMachine and VirtualMachineInstance custom resources, letting a VM be created, updated, and deleted with the same kubectl-based workflow used for any other Kubernetes object. Under the hood, each VM runs inside a pod containing a containerized QEMU process managed by libvirt on top of the Linux kernel's KVM hypervisor, while a companion CLI called virtctl adds VM-specific commands like start, stop, pause, console access, and image management alongside standard kubectl.$q$, $q$Because VMs are ordinary Kubernetes resources, they integrate directly with existing storage classes, CSI drivers, and CNI networking plugins. Live migration lets a running VM move between nodes with no or minimal downtime using pre-copy memory migration, useful for planned maintenance, load balancing, or responding to node failures.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$KubeVirt is free and open source under the Apache 2.0 license, with no cost to download and run on any Kubernetes cluster whose nodes support hardware virtualization (KVM). Community support is available through the CNCF Slack and GitHub.$q$, $q$Organizations that want commercial support generally adopt KubeVirt through a vendor distribution, most notably Red Hat OpenShift Virtualization, which bundles KubeVirt with enterprise support, a management UI, and additional operational tooling.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('66cb57df-a72f-4b48-8e7c-dd2074ba5b6e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Peer-to-Peer Recognition Feed$q$, $q$A live activity feed where employees give and see public recognition tied to company values.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Milestone and Anniversary Celebrations$q$, $q$Automated virtual cards and callouts for work anniversaries, birthdays, and other milestones.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Manager-Driven and Nomination Awards$q$, $q$Structured award and nomination programs for manager-led recognition campaigns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Rewards and Redemption Catalog$q$, $q$Optional points-based reward catalog employees can redeem for gift cards or merchandise.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$People Analytics Dashboard$q$, $q$Insights into recognition trends, participation rates, and engagement by team, tied back to company values.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Incentive Programs$q$, $q$Configurable campaigns to reward specific target behaviors beyond ad hoc recognition.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Integrations$q$, $q$Connects with HRIS and collaboration tools such as Microsoft Teams, Slack, ADP, and UKG.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Mobile Access$q$, $q$Recognition and rewards accessible through Kudos' mobile apps in addition to the web platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Highly configurable to map recognition directly to company-defined core values$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Rich analytics give leadership visibility into which values show up in daily work$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Broad set of recognition types (peer, manager, milestone, nomination) in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Integrates with major HRIS and collaboration tools like Teams, Slack, ADP, and UKG$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Positioned as a data-driven engagement tool, not just a rewards catalog$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Pricing is not published and requires a custom quote from sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Reward redemption catalog is an optional add-on rather than included by default$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Smaller brand footprint than category leaders like Bonusly, Nectar, or Motivosity, meaning fewer public benchmarks$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Effectiveness depends heavily on manager and leadership buy-in to drive adoption$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Company founding and history details are less transparently documented than some larger competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$What does Kudos do?$q$, $q$Kudos is an employee recognition and rewards platform that lets coworkers and managers publicly recognize each other, tied to specific company values, while giving leadership analytics on engagement and culture.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$How much does Kudos cost?$q$, $q$Kudos does not publish fixed pricing; it uses a custom subscription quote based on company size and features, with one reported real-world price point of around $3 per employee per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Where is Kudos based?$q$, $q$Kudos is headquartered in Calgary, Alberta, Canada, with additional offices supporting the US and European markets.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Does Kudos integrate with Microsoft Teams and Slack?$q$, $q$Yes, Kudos integrates with collaboration tools such as Microsoft Teams and Slack as well as major HR platforms like ADP and UKG.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Is Kudos only for large enterprises?$q$, $q$No, Kudos is used by organizations of varying sizes, though its analytics and configuration depth are particularly aimed at mid-size and larger companies wanting structured recognition programs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Does Kudos have a rewards catalog?$q$, $q$Yes, Kudos offers an optional points-based reward catalog that employees can redeem alongside its core social recognition feed.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Company-wide culture and values reinforcement$q$, $q$Tie every recognition post to a specific company value so leadership can track which values are actually lived out day to day.$q$, $q$HR and People teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Manager recognition programs$q$, $q$Run structured, manager-driven award and nomination campaigns to spotlight top performers on a regular cadence.$q$, $q$People managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Remote and distributed team engagement$q$, $q$Keep remote employees visible and appreciated through a shared digital recognition feed and milestone celebrations.$q$, $q$Distributed workforces$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$Custom Subscription$q$, $q$Custom pricing (reportedly around $3/employee/month for the standard platform)$q$, $q$Monthly or annual$q$, NULL, $q$["Peer and manager recognition feed","Milestone and anniversary celebrations","People analytics dashboard","HRIS and collaboration tool integrations","Optional rewards redemption catalog"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kudos is an employee recognition and rewards platform headquartered in Calgary, Alberta, Canada, generally reported as founded around 2010, that helps organizations build a culture of appreciation through structured, values-linked peer and manager recognition. The company has grown to roughly 90 employees and raised 10 million dollars in 2022 to expand its Calgary workforce and product investment.$q$, $q$The platform's central design choice is requiring every recognition post to be tied to one of a company's defined core values, which turns everyday praise into a structured dataset leadership can use to see which values genuinely show up in daily work, rather than functioning as a purely social thank-you wall.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kudos combines a live peer-to-peer recognition feed with milestone and work-anniversary celebrations, manager-driven award programs, structured nomination campaigns, and configurable incentive programs aimed at reinforcing specific behaviors. An optional points-based rewards catalog lets organizations attach tangible redemptions, such as gift cards, to recognition for companies that want more than social acknowledgment.$q$, $q$A people analytics dashboard gives HR and leadership visibility into recognition volume, participation, and which company values are being reinforced across teams, while integrations with Microsoft Teams, Slack, and HR platforms such as ADP and UKG keep recognition embedded in tools employees already use, supported by a mobile app for distributed and frontline staff.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kudos does not publish fixed pricing tiers; the platform uses a custom subscription model priced according to organization size, chosen features, and whether the optional rewards redemption catalog is included, typically billed monthly or annually.$q$, $q$One independently reported data point places real-world pricing at around three dollars per employee per month for the standard platform, though prospective buyers should expect to request a demo and custom quote rather than finding self-serve pricing on the company's website.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45bbc3cd-e3e9-484a-8307-e4b104d0b92c', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Unified Customer Timeline$q$, $q$Combines every conversation, order, and interaction across channels into a single CRM-based customer record instead of a ticket queue.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Omnichannel Messaging$q$, $q$Handles chat, email, SMS/text, voice, and social channels including WhatsApp, Instagram, and Facebook from one inbox.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Workflow Automation and Routing$q$, $q$Configurable queues and rules to automatically route and prioritize conversations to the right agent or team.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Kustomer AI (Concierge, Envoy, Copilot)$q$, $q$AI tools for customer-facing deflection, guided self-service, and an AI Agent Team Assistant that helps human agents draft responses.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Reporting and Analytics$q$, $q$Built-in dashboards and reporting on volume, resolution time, CSAT, and team performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Security and Compliance Controls$q$, $q$SSO, SAML, data masking, and an optional HIPAA-enabled subscription for regulated industries.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Extensive Integrations$q$, $q$Outbound and inbound webhooks, custom attributes, and native connections to e-commerce, CRM, and Meta-owned messaging channels.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$CRM-First Data Model$q$, $q$Stores structured customer data such as orders, loyalty status, and shipping info directly on the customer record rather than as separate ticket metadata.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Unifies customer history across channels into one CRM-style profile instead of siloed tickets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Strong native support for Meta-owned channels like WhatsApp, Instagram, and Messenger$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Flexible workflow and queue automation for complex support organizations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$AI copilot and AI Agent tools built directly into the platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Well suited for mid-size to enterprise teams with high support volume$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Pricing is not published and generally targets mid-market and enterprise budgets, with an 8-seat minimum reported by third parties$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$AI features such as AI Agent conversations and copilot seats are billed as separate add-ons on top of base seat price$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Steeper learning curve and setup effort than simpler help desk tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Less suited to very small teams or solo founders due to enterprise-oriented pricing and complexity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Ownership changes (acquired by Meta, then spun out) have created some uncertainty about long-term roadmap continuity$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Is Kustomer still owned by Meta?$q$, $q$No. Facebook (Meta) acquired Kustomer for about $1 billion in a deal announced in November 2020 and closed in February 2022, but Meta spun Kustomer out as an independent company again in May 2023 with $60 million in new funding from previous backers at a $250 million valuation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Who founded Kustomer?$q$, $q$Kustomer was founded in 2015 by Brad Birnbaum and Jeremy Suriel, who previously worked together and had sold a prior startup to Salesforce.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$What makes Kustomer different from Zendesk or Intercom?$q$, $q$Kustomer is built around a CRM-style customer timeline that unifies order, shipping, and interaction history in one profile, whereas Zendesk is more traditionally a structured ticketing help desk and Intercom is built primarily around in-app messaging.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$How much does Kustomer cost?$q$, $q$Kustomer does not publish list prices; third-party trackers report Enterprise seats around $89/agent/month and Ultimate seats around $139/agent/month, both billed annually with an 8-seat minimum, plus separate charges for AI features.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Does Kustomer support WhatsApp and Instagram?$q$, $q$Yes, Kustomer natively supports WhatsApp, Instagram Direct, and Facebook Messenger alongside chat, email, SMS, and voice channels.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Is Kustomer good for small businesses?$q$, $q$Kustomer is generally positioned for mid-size to enterprise support teams handling high conversation volume rather than very small businesses, given its seat minimums and enterprise-style pricing.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$High-volume omnichannel support teams$q$, $q$Consolidate chat, email, voice, and social messaging into one queue-routed inbox tied to a unified customer profile.$q$, $q$Mid-size to enterprise customer service organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$E-commerce and retail customer service$q$, $q$Surface order, shipping, and loyalty data directly alongside conversations to resolve issues faster.$q$, $q$E-commerce brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Messaging-first support on Meta channels$q$, $q$Manage and automate conversations across Meta-owned messaging channels from a single CRM-based platform.$q$, $q$Brands with heavy WhatsApp, Instagram, and Messenger support volume$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Enterprise$q$, $q$Custom pricing (reportedly around $89/agent/month)$q$, $q$Annual, 8-seat minimum$q$, NULL, $q$["Omnichannel messaging","Workflow automation and routing","Reporting and analytics","Standard security controls"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$Ultimate$q$, $q$Custom pricing (reportedly around $139/agent/month)$q$, $q$Annual, 8-seat minimum$q$, NULL, $q$["Everything in Enterprise","Expanded AI and automation capabilities","Advanced security and compliance options"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$AI Add-ons$q$, $q$Usage-based (reportedly around $0.60 per AI Agent conversation, plus per-seat copilot pricing)$q$, $q$Usage-based / per seat$q$, NULL, $q$["AI Agent for customer conversations","AI copilot for human agents","Optional HIPAA-enabled subscription"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kustomer is a CRM-based customer service platform founded in New York in 2015 by Brad Birnbaum and Jeremy Suriel. Rather than organizing support around isolated tickets, Kustomer unifies every customer conversation and related data, such as orders and shipping status, into a single ongoing timeline.$q$, $q$The company's history includes a high-profile 1 billion dollar acquisition by Facebook (Meta) announced in November 2020 and closed in February 2022, intended to strengthen Meta's business messaging push across WhatsApp, Instagram, and Messenger. In May 2023, as part of Meta's broader efficiency push, Kustomer was spun back out as an independent company with 60 million dollars in new funding from previous backers at a 250 million dollar valuation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kustomer supports omnichannel messaging across chat, email, SMS, voice, and, reflecting its Meta history, deep native integration with WhatsApp, Instagram Direct, and Facebook Messenger. Configurable workflow automation and queue-based routing let teams control how conversations get prioritized and assigned, while Kustomer AI tools, including a customer-facing Concierge/Envoy and an agent-facing AI copilot, add automation and deflection on top of the core CRM timeline.$q$, $q$Enterprise-oriented capabilities include SSO and SAML, data masking, a HIPAA-enabled subscription add-on, and an extensive webhook and custom-attribute system for integrating with e-commerce platforms and other backend systems, alongside built-in reporting and analytics dashboards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kustomer does not publish list pricing and instead routes prospective buyers to a sales conversation. Third-party pricing trackers report Enterprise seats at roughly 89 dollars per agent per month and Ultimate seats at roughly 139 dollars per agent per month, both typically billed annually with an eight-seat minimum.$q$, $q$AI features are generally billed separately from base seats, with reported figures around 0.60 dollars per AI Agent conversation and around 40 dollars per user per month for the AI copilot add-on, meaning a realistic total cost includes both the seat tier and any AI usage on top of it.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45cee20f-f1da-4f5d-86e5-485b9a0b34b6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Flat-Rate Unlimited Users$q$, $q$Charges one flat monthly fee per organization instead of per-seat pricing, so teams can add unlimited users on paid plans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Lead, Contact, and Deal Management$q$, $q$Core CRM objects for tracking leads, contacts, companies, and sales pipelines.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Workflow Automation$q$, $q$Configurable workflows to automate follow-ups, lead assignment, and repetitive sales tasks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Telephony, Email, and WhatsApp Integration$q$, $q$Built-in calling, email sync, and SMS/WhatsApp messaging from within the CRM.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Reports and Dashboards$q$, $q$Pre-built and customizable reports and dashboards for pipeline and performance visibility.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Mobile App and Field Sales Tracking$q$, $q$Mobile access plus an add-on for tracking field sales team activity and location.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Custom Fields and Records Scaling$q$, $q$Expandable record limits and custom fields that scale with add-ons as a business grows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$BI Analytics Add-on$q$, $q$Optional business intelligence and analytics module for deeper pipeline insight.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Flat, predictable pricing with unlimited users rather than per-seat fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Genuinely usable free (Embark) tier with 10,000 records and unlimited users$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Built-in telephony, email, and WhatsApp/SMS integration without extra tooling$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Self-funded, profitable-leaning company with steady product investment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Simple setup aimed specifically at SMB sales teams rather than complex enterprise configuration$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Flat-rate pricing from $250/month can be more expensive than per-seat competitors for very small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Many features, such as extra workflows, email templates, custom fields, and BI analytics, are metered as paid add-ons$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Smaller ecosystem of third-party integrations and marketplace apps than Salesforce, HubSpot, or Zoho$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Primarily focused on sales CRM, without the broader marketing and service hub breadth of platforms like HubSpot$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Less brand recognition and fewer public case studies outside its core India and SMB market$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Is Kylas free?$q$, $q$Yes, Kylas offers a free-forever Embark plan with unlimited users and up to 10,000 records; paid plans start with Elevate at a flat rate from around $250 per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Who founded Kylas and when?$q$, $q$Kylas was founded in 2020 by Vikram Kotnis and is headquartered in Pune, India.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$How is Kylas priced compared to other CRMs?$q$, $q$Kylas uses flat-rate pricing per organization with unlimited users, unlike most competitors such as Zoho CRM, Freshsales, or Salesforce, which charge per user per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$What CRM features does Kylas include?$q$, $q$Kylas includes lead and pipeline management, workflow automation, telephony and WhatsApp/email integration, reporting and dashboards, and a mobile app, with more advanced features like BI analytics available as add-ons.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$What are the main Kylas alternatives?$q$, $q$Common alternatives include Zoho CRM, HubSpot Sales Hub, Freshsales, Pipedrive, and Salesforce Sales Cloud.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Does Kylas offer phone support?$q$, $q$Phone support and a dedicated account manager are included in the top-tier Exceed plan; the Elevate plan includes email support.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$SMB sales teams outgrowing spreadsheets$q$, $q$Move lead and pipeline tracking off spreadsheets into a structured CRM without paying per-seat fees as the team grows.$q$, $q$Small and mid-sized sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Growing sales orgs needing flat-fee scaling$q$, $q$Add unlimited sales reps under one flat monthly price instead of renegotiating per-seat contracts.$q$, $q$Scaling sales departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Field sales operations$q$, $q$Use the mobile app and field sales tracking add-on to log visits, calls, and deal progress from outside the office.$q$, $q$Field sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Embark$q$, $q$Free$q$, $q$Lifetime free$q$, NULL, $q$["Unlimited users","10,000 records","Lead, contact, and company management","Basic pipeline management","Mobile app","Task management and reminders","Pre-built reports and dashboards"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Elevate$q$, $q$From $250/month, flat rate$q$, $q$Monthly, quarterly, half-yearly, or annual$q$, NULL, $q$["Everything in Embark","100,000 records","30 workflows","Email and calendar sync","SMS and WhatsApp integration","Telephony integration","30 email templates","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$Exceed$q$, $q$Custom pricing$q$, $q$Custom$q$, NULL, $q$["Everything in Elevate","1,100,000+ records","130+ workflows","80+ email templates","125+ custom fields","Advanced security","Phone support and dedicated account manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Kylas is a cloud-based sales CRM founded in 2020 by Vikram Kotnis and headquartered in Pune, India, built specifically for small and mid-sized business sales teams. The company has grown as a self-funded business, reportedly reaching around 7.6 million dollars in annual recurring revenue without raising outside venture capital.$q$, $q$Kylas's defining feature is flat-rate, unlimited-user pricing: instead of charging per seat like most CRM vendors, it charges one flat monthly fee per organization regardless of team size, aiming to give growing sales teams predictable costs as they add headcount.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Kylas covers core sales CRM functionality including lead, contact, and company management, deal and pipeline tracking, task management and reminders, and customizable reports and dashboards. Built-in telephony, email sync, and SMS/WhatsApp integration let reps communicate and log interactions without leaving the CRM, while workflow automation handles lead assignment and repetitive follow-up tasks.$q$, $q$A mobile app and a field sales tracking add-on extend the CRM to reps working outside the office, and a BI analytics add-on offers deeper pipeline insight for teams that outgrow the standard reporting included in paid plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Kylas uses a three-tier structure: Embark is free forever with unlimited users and up to 10,000 records; Elevate is a flat rate reported at around 250 dollars per month with expanded records, workflows, and communication integrations, offered with a 7-day free trial; and Exceed is custom-priced for larger teams needing advanced security, phone support, and a dedicated account manager.$q$, $q$On top of the core tiers, Kylas sells granular add-ons priced in Indian rupees for extra email templates, workflows, records, custom fields, storage, and field sales tracking, plus one-time onboarding packages, letting customers scale capacity incrementally rather than jumping a full plan tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('75d9ec55-139d-48db-86d9-199f725ad9e3', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
